package media

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/plugin/media"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type MediaServiceProxy struct {
	media.UnimplementedMediaServiceServer
	client media.MediaServiceClient
}

func init() {
	proxyutil.Register(&media.MediaService_ServiceDesc, NewMediaServiceProxy)
}
func NewMediaServiceProxy(cc grpc.ClientConnInterface) media.MediaServiceServer {
	return &MediaServiceProxy{client: media.NewMediaServiceClient(cc)}
}
func (p *MediaServiceProxy) Upload(ctx context.Context, in *media.MediaUploadRequest) (*media.MediaUploadResponse, error) {
	return proxyutil.ProxyMethod[media.MediaUploadRequest, media.MediaUploadResponse](p.client.Upload)(ctx, in)
}
